head.script:
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.pos_groupCode = 0;    // 저장전 DataSet의 RowPosition을 저장 변수 
    scwin.gv_loabranCd = $c.data.getMemInfo('loUpperLobranCd')
    scwin.curDate = $c.date.getServerDateTime();

    scwin.f_switchObjMode(1);
    const codeOptions = [
        { grpCd: "OP182", compID: "gr_results1:wrkUnitCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    const comboOptions = [
        {
            method: "getLuxeComboData",
            param1: "LoBranEBC",
            param2: "retriveLoBranUpperList",
            compID: "lc_lobranCd"
        }
    ];
    $c.data.setGauceUtil(comboOptions, function () {
        lc_lobranCd.setValue(scwin.gv_loabranCd);
    });
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    udc_fromToCalendar.setInitDate(scwin.curDate.substring(0, 6) + "01", scwin.curDate);
    ed_stDt.focus();
};

//-------------------------------------------------------------------------
// 화면구성요소 제어(버튼 입력박스등등 disable, enable) > 1, 4, 5만 사용
//-------------------------------------------------------------------------
scwin.f_switchObjMode = function (gubun) {
    switch (gubun) {
        case 1:	//화면로딩
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_save]);
            $c.gus.cfDisableObjects([btn_custom]);
            $c.gus.cfDisableObjects([udc_btGrdBtn, udc_btGrdBtn1]);
            break;
        case 2:	//조회
            break;
        case 3:	//신규
            break;
        case 4:	//수정
            $c.gus.cfEnableBtnOnly([btn_save]);
            $c.gus.cfEnableObjects([udc_btGrdBtn, udc_btGrdBtn1]);
            break;
        case 5:	//조회완료
            $c.gus.cfEnableBtnOnly([btn_save]);
            $c.gus.cfEnableObjects([udc_btGrdBtn, udc_btGrdBtn1]);
            break;
        case 6:	//수정불가
            break;
        case 7: //행삭제, 취소
            break;
        case 8:	//행추가
            break;
        default:
            break;
    }
};

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, row) {
    switch (disGubun) {
        case 1:	//협력업체조회
            udc_clntNo.cfCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_copCoClntNm),
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;

        case 2:	//도구종류
            udc_eqKndCd.cfCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_eqKndCd, ed_hveqKndNm),
                pCode, pName, pClose, null, "코드,코드명", null, null, null, null, null, null, null, null, pAllSearch, "중기종류조회,코드,코드명");
            break;

        case 3:	//협력업체조회(grid)
            pCode = ds_results.getCellData(row, "clntNo");
            pName = ds_results.getCellData(row, "clntNm");

            if (pCode == " ") {
                ds_results.setCellData(row, "clntNo", " ");
                ds_results.setCellData(row, "clntNm", "공통요율");
                break;
            } else if (pName == "공통요율") {
                ds_results.setCellData(row, "clntNo", " ");
                ds_results.setCellData(row, "clntNm", "공통요율");
                break;
            } else if (pCode.toUpperCase() == "ZZZZZZ") {
                ds_results.setCellData(row, "clntNo", "ZZZZZZ");
                ds_results.setCellData(row, "clntNm", "협정요율");
                break;
            } else if (pName == "협정요율") {
                ds_results.setCellData(row, "clntNo", "ZZZZZZ");
                ds_results.setCellData(row, "clntNm", "협정요율");
                break;
            }

            pCode = ds_results.getCellData(row, "clntNo").replace(/\s*$/, '').toUpperCase();
            pName = ds_results.getCellData(row, "clntNm").replace(/\s*$/, '');
            ds_results.setCellData(row, "clntNo", "");
            ds_results.setCellData(row, "clntNm", "");
            udc_comCode.setSelectId("retrieveHeavyMachineryClntInfo");
            let rtnList = await udc_comCode.cfCommonPopUpAsync((rtnList) => $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "clntNo", "clntNm")
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , null
            );
            break;

        case 4:	//중기조회(grid)
            pCode = ds_results1.getCellData(row, "eqKndCd").replace(/\s*$/, '').toUpperCase();
            pName = ds_results1.getCellData(row, "eqKndNm");
            ds_results1.setCellData(row, "eqKndCd", "");
            ds_results1.setCellData(row, "eqKndNm", "");
            eqNrmCd = ds_results1.getCellData(row, "eqNrmCd");
            eqNrmNm = ds_results1.getCellData(row, "eqNrmNm");
            ds_results1.setCellData(row, "eqNrmCd", "");
            ds_results1.setCellData(row, "eqNrmNm", "");
            udc_comCode.setSelectId("retrieveHeavyMachineryKind2");
            await udc_comCode.cfCommonPopUpAsync((rtnList) => {
                $c.gus.cfSetGridReturnValue(rtnList, ds_results1, row, "eqKndCd", "eqKndNm");
                if (rtnList != null && rtnList[0] != "N/A") {
                    ds_results1.setCellData(row, "eqNrmCd", eqNrmCd);
                    ds_results1.setCellData(row, "eqNrmNm", eqNrmNm);
                }
            }
                , pCode
                , pName
                , pClose
                , null
                , "코드,코드명"
                , null
                , null
                , null
                , '440'
                , '500'
                , null
                , null
                , null
                , pAllSearch
                , "중기종류조회,코드,코드명"
            );
            break;

        case 5:	//장비규격조회(grid)
            pCode = ds_results1.getCellData(row, "eqNrmCd").replace(/\s*$/, '');
            pName = ds_results1.getCellData(row, "eqNrmNm");
            let pWtitleSearch = "ZZ208," + ds_results1.getCellData(row, "eqKndCd");
            udc_comCode.setSelectId("retrieveDsCommCdInfo");
            await udc_comCode.cfCommonPopUpAsync((rtnList) => $c.gus.cfSetGridReturnValue(rtnList, ds_results1, row, "eqNrmCd", "eqNrmNm")
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWtitleSearch
                , '440'
                , '500'
                , null
                , null
                , null
                , pAllSearch
                , "중기규격조회,코드,코드명"
            );
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 공통 팝업 호출
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        await scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        await scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    // 검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([ed_stDt, ed_endDt])) {
        return;
    }

    if (lc_lobranCd.getValue() == "") {
        await $c.win.alert("점소를 입력하십시요.");
        lc_lobranCd.focus();
        return;
    }

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 협력업체정보 그리드 클릭 > 중기별임차요율 filter
//-------------------------------------------------------------------------
scwin.f_result1Filter = function (row) {
    ds_results1.clearFilter();
    let rowObj = ds_results.getRowJSON(row);
    $c.data.dataListFilter("ds_results1", `stDt=='${rowObj.stDt}'&&ctrtEndDt=='${rowObj.ctrtEndDt}'&&clntNo=='${rowObj.clntNo}'`);
    if (ds_results1.getRowCount()) {
        gr_results1.setFocusedCell(0, gr_results1.getFocusedColumnIndex() ?? 0, false);
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (!ds_results.getRowCount()) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["임차료율"]);
        return;
    }
    // 검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([gr_results], null, true)) {
        return;
    }

    if (!await $c.gus.cfValidate([gr_results1], null, true)) {
        return;
    }

    if (!ds_results1.getRowCount()) {
        $c.gus.f_cfAlertMsg("요율이 등록되지 않았습니다");
        return;
    }

    for (let i = 0; i < ds_results.getRowCount(); i++) {
        let v_stDt = ds_results.getCellData(i, "stDt");
        let v_ctrtEndDt = ds_results.getCellData(i, "ctrtEndDt");
        if (v_stDt.trim().length != 8 || v_ctrtEndDt.trim().length != 8 || !$c.gus.cfIsAfterDate(v_stDt, v_ctrtEndDt, false)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
            return false;
        }
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        scwin.pos_groupCode = gr_results.getFocusedRowIndex();  // 저장 전의 위치 저장
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    let row = gr_results.getFocusedRowIndex();
    let stDt = ed_stDt.getValue();
    let ctrtEndDt = ed_endDt.getValue();
    if (row === null || row < 0) {
        row = ds_results.insertRow();
    } else {
        let v_ctrtEndDt = ds_results.getCellData(row, "ctrtEndDt");
        row = ds_results.insertRow(row + 1);

        stDt = $c.date.addDate(v_ctrtEndDt, 1);
        ctrtEndDt = $c.date.addMonth(v_ctrtEndDt, 1);
    }
    ds_results.setCellData(row, "stDt", stDt);
    ds_results.setCellData(row, "ctrtEndDt", ctrtEndDt);
    gr_results.setFocusedCell(row, gr_results.getFocusedColumnIndex() ?? 0, false);

    scwin.f_result1Filter(row);
};

scwin.f_AddRow1 = async function () {
    if (!await $c.gus.cfValidate([gr_results1], null, true)) {
        return
    };

    let row1 = gr_results1.getFocusedRowIndex();
    if (row1 === null || row1 < 0) {
        row1 = ds_results1.insertRow();
    } else {
        row1 = ds_results1.insertRow(row1);
    }
    let data = ds_results.getRowJSON(gr_results.getFocusedRowIndex());
    ds_results1.setCellData(row1, "stDt", data.stDt);
    ds_results1.setCellData(row1, "ctrtEndDt", data.ctrtEndDt);
    ds_results1.setCellData(row1, "endDt", "99999999");
    ds_results1.setCellData(row1, "lobranCd", lc_lobranCd.getValue());
    ds_results1.setCellData(row1, "clntNo", data.clntNo);
    ds_results1.setCellData(row1, "clntNm", data.clntNm);
    ds_results1.setCellData(row1, "eqKndCd", ed_eqKndCd.getValue());
    ds_results1.setCellData(row1, "eqKndNm", ed_hveqKndNm.getValue());
    ds_results1.setCellData(row1, "upr", "0");
    gr_results1.setFocusedCell(row1, gr_results1.getFocusedColumnIndex() ?? 0);
};

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function () {
    let row1 = gr_results1.getFocusedRowIndex();
    let row = gr_results.getFocusedRowIndex();
    let data = ds_results.getRowJSON(row);
    let matched = [];
    if ("" == data.stDt && "" == data.ctrtEndDt && "" == data.clntNo) {
        matched.push(row1);
    } else {
        if (gr_results1.getRowCount()) {
            let allData = ds_results1.getAllFilteredJSON();
            for (let idx = 0; idx < allData.length; ++idx) {
                let rowObj = allData[idx];
                if (rowObj.stDt == data.stDt && rowObj.ctrtEndDt == data.ctrtEndDt && rowObj.clntNo == data.clntNo) {
                    matched.unshift(idx);
                }
            }
        }
    }
    for (let idx of matched) {
        if (ds_results1.getRowStatus(idx) == "C") {
            ds_results1.removeRow(idx);
        } else {
            ds_results1.deleteRow(idx);
        }
    }
    if (gr_results.getFocusedRowStatus() == "C") {
        ds_results.removeRow(row);
        if (row >= ds_results.getRowCount()) {
            row = ds_results.getRowCount() - 1;
        } else {
            scwin.gr_results_onrowindexchange(row);
        }
    } else {
        ds_results.deleteRow(row);
    }
    gr_results.setFocusedCell(row, gr_results.getFocusedColumnIndex() ?? 0, false);
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    scwin.undoAll(ds_results1);
    scwin.undoRow(ds_results, gr_results.getFocusedRowIndex());
};

scwin.f_Cancel1 = function () {
    scwin.undoAll(ds_results1);
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, [ed_stDt, ed_endDt]);
};

//-------------------------------------------------------------------------
// Formatter
//-------------------------------------------------------------------------
scwin.f_customFormatter = function (data, formattedData, row, colIndex) {
    return $c.gus.decode(ds_results1.getCellData(row, "endDt"), "99999999", "Y", "N");
};

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//저장 성공
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return;
    }

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};

//조회 성공
scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        return;
    }

    $c.gus.cfGoPrevPosition(gr_results, scwin.pos_groupCode);  // 저장전 위치로 이동
    let rowCnt = ds_results.getRowCount();
    spn_totalRow.setValue(rowCnt);

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        scwin.f_switchObjMode(1);
        scwin.f_switchObjMode(5);
        return;
    } else {
        gr_results1.setFocusedCell(0, gr_results1.getFocusedColumnIndex() ?? 0, false);
    }

    scwin.f_switchObjMode(4);
};

/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//조회영역 협력업체 찾기 버튼
scwin.udc_clntNo_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(1, ed_clntNo.getValue().trim(), ed_copCoClntNm.getValue().trim(), 'F', 'T');
};

scwin.udc_clntNo_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_clntNo, ed_copCoClntNm, 1);
};

scwin.udc_clntNo_onviewchangeNameEvent = async function (info) {
    await scwin.f_chkOpenCommonPopUp(ed_copCoClntNm, ed_clntNo, 1, false);
};

//조회영역중기종류 찾기 버튼
scwin.udc_eqKndCd_onclickEvent = async function (e) {
    await scwin.f_openCommonPopUp(2, ed_eqKndCd.getValue().trim(), ed_hveqKndNm.getValue().trim(), 'F', 'T')
};

scwin.udc_eqKndCd_onblurCodeEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_eqKndCd, ed_hveqKndNm, 2);
};

scwin.udc_eqKndCd_onblurNameEvent = async function (e) {
    await scwin.f_chkOpenCommonPopUp(ed_hveqKndNm, ed_eqKndCd, 2, false);
};


//조회조건 clear 버튼
scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

//조회 버튼
scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

//종류선택 버튼
scwin.btn_custom_onclick = async function (e) {
    await $c.win.alert("버튼 삭제여부 확인필요");
    return;
};

//저장 버튼
scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

//협력업체정보 그리드 row 변경
scwin.gr_results_onrowindexchange = function (row, oldRow) {
    if (ds_results.getRowStatus(row) == "C") {	//인서트인경우
        gr_results.setReadOnly("cell", row, "stDt", false);
        gr_results.setReadOnly("cell", row, "ctrtEndDt", false);
        gr_results.setReadOnly("cell", row, "clntNo", false);
        gr_results.setReadOnly("cell", row, "clntNm", false);
    } else {
        gr_results.setReadOnly("cell", row, "stDt", true);
        gr_results.setReadOnly("cell", row, "clntNo", true);
        gr_results.setReadOnly("cell", row, "clntNm", true);
    }

    scwin.f_result1Filter(row);
    //scwin.f_switchObjMode(4);
};

//협력업체정보 그리드 코드 클릭
scwin.gr_results_ontextimageclick = async function (row, col) {
    if (gr_results.getFocusedRowStatus() != "C") {
        return;
    }
    let colid = gr_results.getColumnID(col);
    if (colid == "clntNo") {
        await scwin.f_openCommonPopUp(3, null, null, 'F', 'T', row);
    }
};

//협력업체정보 그리드 값 변경
scwin.gr_results_onviewchange = async function (info) {
    let row = info.rowIndex;
    let colid = gr_results.getColumnID(info.colIndex);
    switch (colid) {
        case "clntNo":
            //v_clntNo = info.oldValue;
            if (info.newValue != "" && info.oldValue != info.newValue) {
                ds_results.setCellData(row, "clntNm", "");
                await scwin.f_openCommonPopUp(3, null, null, 'T', 'T', row);
            } else if (ds_results.getCellData(row, colid) == "") {
                ds_results.setCellData(row, "clntNo", "");
                ds_results.setCellData(row, "clntNm", "");
            }
            break;

        case "clntNm":
            //v_clntNo = info.oldValue;
            if (info.newValue != "" && info.oldValue != info.newValue) {
                ds_results.setCellData(row, "clntNo", "");
                await scwin.f_openCommonPopUp(3, null, null, 'T', 'T', row);
            } else if (ds_results.getCellData(row, colid) == "") {
                ds_results.setCellData(row, "clntNo", "");
                ds_results.setCellData(row, "clntNm", "");
            }
            break;
    }

    let rowObj = ds_results.getRowJSON(row);
    if (info.newValue != info.oldValue) {
        for (let i = 0; i < ds_results1.getRowCount(); i++) {
            ds_results1.setCellData(i, "stDt", rowObj.stDt);
            ds_results1.setCellData(i, "ctrtEndDt", rowObj.ctrtEndDt);
            ds_results1.setCellData(i, "clntNo", rowObj.clntNo);
        }
    }

    //좌측그리드에서 커서가 떠날때 무조건 우측으로 복사
    for (let i = 0; i < ds_results1.getRowCount(); i++) {
        ds_results1.setCellData(i, "stDt", rowObj.stDt);
        ds_results1.setCellData(i, "ctrtEndDt", rowObj.ctrtEndDt);
        ds_results1.setCellData(i, "lobranCd", lc_lobranCd.getValue());
        ds_results1.setCellData(i, "clntNo", rowObj.clntNo);
        ds_results1.setCellData(i, "clntNm", rowObj.clntNm);
    }

    scwin.f_result1Filter(row);
};

//중기별임차요율 그리드 row 변경
scwin.gr_results1_onrowindexchange = function (row, oldRow) {
    if (ds_results1.getRowStatus(row) == "C") {	//인서트인경우
        gr_results1.setReadOnly("cell", row, "eqKndCd", false);
        gr_results1.setReadOnly("cell", row, "eqKndNm", false);
        gr_results1.setReadOnly("cell", row, "eqNrmNm", false);
        gr_results1.setReadOnly("cell", row, "wrkUnitCd", false);
        gr_results1.setReadOnly("cell", row, "upr", false);
        gr_results1.setReadOnly("cell", row, "nowYn", true);
    } else {
        gr_results1.setReadOnly("cell", row, "eqKndCd", true);
        gr_results1.setReadOnly("cell", row, "eqKndNm", true);
        gr_results1.setReadOnly("cell", row, "eqNrmNm", true);
        gr_results1.setReadOnly("cell", row, "wrkUnitCd", true);
        gr_results1.setReadOnly("cell", row, "upr", false);
        gr_results1.setReadOnly("cell", row, "nowYn", true);
    }
};

//중기별임차요율 그리드 값 변경
scwin.gr_results1_onviewchange = async function (info) {
    let row = info.rowIndex;
    let colid = gr_results1.getColumnID(info.colIndex);
    switch (colid) {
        case "eqKndCd":
            info.newValue = info.newValue.toUpperCase();
            ds_results1.setCellData(row, colid, info.newValue);
            if (info.newValue != "") {
                ds_results1.setCellData(row, "eqKndNm", "");
                await scwin.f_openCommonPopUp(4, null, null, 'T', 'T', row);
            } else {
                ds_results1.setCellData(row, "eqKndCd", "");
                ds_results1.setCellData(row, "eqKndNm", "");
                ds_results1.setCellData(row, "eqNrmCd", "");
                ds_results1.setCellData(row, "eqNrmNm", "");
            }
            break;

        case "eqKndNm":
            if (info.newValue != "") {
                ds_results1.setCellData(row, "eqKndCd", "");
                await scwin.f_openCommonPopUp(4, null, null, 'T', 'T', row);
            } else {
                ds_results1.setCellData(row, "eqKndCd", "");
                ds_results1.setCellData(row, "eqKndNm", "");
                ds_results1.setCellData(row, "eqNrmCd", "");
                ds_results1.setCellData(row, "eqNrmNm", "");
            }
            break;

        case "eqNrmNm":
            if (info.newValue != "") {
                let v_eqKndCd = ds_results1.getCellData(row, "eqKndCd");
                if (v_eqKndCd == null || v_eqKndCd == "") {
                    ds_results1.setCellData(row, "eqNrmCd", "");
                    ds_results1.setCellData(row, "eqNrmNm", "");
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["중기코드"]); // 중기코드가 존재하지 않습니다
                    return;
                }
                await scwin.f_openCommonPopUp(5, null, null, 'T', 'T', row);
            } else {
                ds_results1.setCellData(row, "eqNrmCd", "");
            }
            break;

        case "upr":
            if (info.newValue == "" || isNaN(info.newValue)) {
                ds_results1.setCellData(row, "upr", "0");
            }
            break;
    }
};

//중기별임차요율 그리드 코드, 규격 클릭
scwin.gr_results1_ontextimageclick = async function (row, col) {
    if (gr_results1.getFocusedRowStatus() != "C") {
        return;
    }
    let colid = gr_results1.getColumnID(col);

    if (colid == "eqKndCd") {
        await scwin.f_openCommonPopUp(4, null, null, 'F', 'T', row);
    } else if (colid == "eqNrmNm") {
        let v_eqKndCd = ds_results1.getCellData(row, "eqKndCd");
        if (v_eqKndCd == null || v_eqKndCd == "") {
            ds_results1.setCellData(row, "eqNrmCd", "");
            ds_results1.setCellData(row, "eqNrmNm", "");
            await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["중기코드"]); // 중기코드가 존재하지 않습니다
            return;
        }
        await scwin.f_openCommonPopUp(5, null, null, 'F', 'T', row);
    }
};

/**
* method
* @name undoAll
* @description
*/
scwin.undoAll = function (dltObj) {
    dltObj.setBroadcast(false);
    for (let idx = dltObj.getRowCount() - 1; idx >= 0; --idx) {
        if (dltObj.getRowStatus(idx) == "C") {
            dltObj.removeRow(idx);
        } else {
            dltObj.undoRow(idx);
        }
    }
    dltObj.setBroadcast(true, true);
};

/**
* method
* @name undoRow
* @description
*/
scwin.undoRow = function (dltObj, row) {
    if (dltObj.getRowStatus(row) == "C") {
        dltObj.removeRow(row);
    } else {
        dltObj.undoRow(row);
    }
};
